                    MappableBinding(Binding.keyCode(KeyEvent.KEYCODE_NUMPAD_ENTER), MappableBinding.Screen.Reviewer(CardSide.ANSWER))
                )

                val ease3Defaults = listOf(
                    MappableBinding(Binding.keyCode(KeyEvent.KEYCODE_BUTTON_B), MappableBinding.Screen.Reviewer(CardSide.BOTH)),
                    MappableBinding(Binding.keyCode(KeyEvent.KEYCODE_3), MappableBinding.Screen.Reviewer(CardSide.ANSWER)),
                    MappableBinding(Binding.keyCode(KeyEvent.KEYCODE_NUMPAD_3), MappableBinding.Screen.Reviewer(CardSide.ANSWER))
                )

                // The new defaults for Ease 3 (merged)
                val newEase3Defaults = ArrayList(ease3Defaults)
                for (b in recommendedDefaults) {
                    if (!newEase3Defaults.contains(b)) {
                        newEase3Defaults.add(b)
                    }
                }

                migrate(preferences, "binding_FLIP_OR_ANSWER_RECOMMENDED", "binding_FLIP_OR_ANSWER_EASE3", recommendedDefaults, ease3Defaults, newEase3Defaults)

                // Migrate Better -> Ease 4
                // Defaults for Better is empty list
                // Defaults for Ease 4:
                val ease4Defaults = listOf(
                    MappableBinding(Binding.keyCode(KeyEvent.KEYCODE_BUTTON_A), MappableBinding.Screen.Reviewer(CardSide.BOTH)),
                    MappableBinding(Binding.keyCode(KeyEvent.KEYCODE_4), MappableBinding.Screen.Reviewer(CardSide.ANSWER)),
                    MappableBinding(Binding.keyCode(KeyEvent.KEYCODE_NUMPAD_4), MappableBinding.Screen.Reviewer(CardSide.ANSWER))
                )
                val betterDefaults = emptyList<MappableBinding>()
                val newEase4Defaults = ArrayList(ease4Defaults) // No change as betterDefaults is empty

                migrate(preferences, "binding_FLIP_OR_ANSWER_BETTER_THAN_RECOMMENDED", "binding_FLIP_OR_ANSWER_EASE4", betterDefaults, ease4Defaults, newEase4Defaults)
            }

            private fun migrate(
                preferences: SharedPreferences,
                oldKey: String,
                newKey: String,
                oldDefaults: List<MappableBinding>,
                newDefaults: List<MappableBinding>,
                targetDefaults: List<MappableBinding>
            ) {
                // Get effective bindings for old command
                val effectiveOld = if (preferences.contains(oldKey)) {
                    MappableBinding.fromPreferenceString(preferences.getString(oldKey, ""))
                } else {
                    oldDefaults
                }

                // Get effective bindings for new command
                val effectiveNew = if (preferences.contains(newKey)) {
                    MappableBinding.fromPreferenceString(preferences.getString(newKey, ""))
                } else {
                    newDefaults
                }

                // Merge effectiveOld into effectiveNew
                val result = ArrayList(effectiveNew)
                for (b in effectiveOld) {
                    if (!result.contains(b)) {
                        result.add(b)
                    }
                }

                if (listEquals(result, targetDefaults)) {
                    preferences.edit {
                        remove(newKey)
                        remove(oldKey)
                    }
                } else {
                    preferences.edit {
                        putString(newKey, result.toPreferenceString())
                        remove(oldKey)
                    }
                }
            }

            private fun listEquals(l1: List<MappableBinding>, l2: List<MappableBinding>): Boolean {
                if (l1.size != l2.size) return false
                return l1 == l2
            }
